package com.ansh.motoverse.controller;
import org.springframework.http.HttpStatus; import org.springframework.web.bind.MethodArgumentNotValidException; import org.springframework.web.bind.annotation.*; import java.time.LocalDateTime; import java.util.Map;
@RestControllerAdvice public class GlobalExceptionHandler { @ExceptionHandler({IllegalArgumentException.class,IllegalStateException.class}) @ResponseStatus(HttpStatus.BAD_REQUEST) public Map<String,Object> handleBadRequest(RuntimeException exception){return Map.of("timestamp",LocalDateTime.now(),"status",400,"error",exception.getMessage());} @ExceptionHandler(MethodArgumentNotValidException.class) @ResponseStatus(HttpStatus.BAD_REQUEST) public Map<String,Object> handleValidation(MethodArgumentNotValidException exception){String message=exception.getBindingResult().getFieldErrors().stream().findFirst().map(error->error.getField()+" "+error.getDefaultMessage()).orElse("Validation failed"); return Map.of("timestamp",LocalDateTime.now(),"status",400,"error",message);} }
